from __future__ import annotations
import datetime, hashlib, json, uuid
from dataclasses import dataclass, field
from decimal import Decimal, ROUND_HALF_UP

@dataclass
class InvoiceLineItem:
    feature:          str
    model:            str
    prompt_tokens:    int
    completion_tokens: int
    unit_rate_input:  Decimal   # USD per 1K tokens
    unit_rate_output: Decimal
    gross_cost_usd:   Decimal
    credit_usd:       Decimal = Decimal("0")

    @property
    def net_cost_usd(self) -> Decimal:
        return (self.gross_cost_usd - self.credit_usd).quantize(
            Decimal("0.0001"), rounding=ROUND_HALF_UP
        )

@dataclass
class ChargebackInvoice:
    invoice_id:     str = field(default_factory=lambda: str(uuid.uuid4()))
    team:           str = ""
    cost_centre:    str = ""
    billing_period: str = ""       # "2025-06"
    issued_at:      str = field(
        default_factory=lambda: datetime.datetime.utcnow().isoformat()
    )
    line_items:     list[InvoiceLineItem] = field(default_factory=list)
    notes:          list[str] = field(default_factory=list)

    @property
    def total_net_usd(self) -> Decimal:
        return sum(li.net_cost_usd for li in self.line_items)

    def content_hash(self) -> str:
        canonical = json.dumps(
            {
                "invoice_id":     self.invoice_id,
                "team":           self.team,
                "billing_period": self.billing_period,
                "total":          str(self.total_net_usd),
                "lines":          len(self.line_items),
            },
            sort_keys=True,
        )
        return hashlib.sha256(canonical.encode()).hexdigest()

    def to_erp_journal(self) -> dict:
        """Map to a generic ERP journal entry (adapt field names to your ERP)."""
        return {
            "journal_type":    "GenAI-Chargeback",
            "reference":       self.invoice_id,
            "period":          self.billing_period,
            "debit_account":   self.cost_centre,        # team's cost centre
            "credit_account":  "8500-GenAI-Platform",   # platform recovery account
            "amount_usd":      float(self.total_net_usd),
            "description":     f"GenAI consumption — {self.team} — {self.billing_period}",
            "content_hash":    self.content_hash(),
        }
